import { apiRequest, buildApiUrl } from "./apiClient";
import { Course, UserProgress } from "../types/api.types";

export const coursesService = {
  async getAllCourses(): Promise<Course[]> {
    return apiRequest<Course[]>(buildApiUrl("/api/fitness/courses"), {
      method: "GET",
    });
  },

  async getCourseById(courseId: string): Promise<Course> {
    return apiRequest<Course>(buildApiUrl(`/api/fitness/courses/${courseId}`), {
      method: "GET",
    });
  },

  async getUserCourses(token: string): Promise<string[]> {
    try {
      const response = await apiRequest<{ email: string; selectedCourses: string[] }>(
        buildApiUrl("/api/fitness/users/me"),
        {
          method: "GET",
          headers: {
            Authorization: `Bearer ${token}`,
          },
        }
      );
      return response.selectedCourses || [];
    } catch (error) {
      console.warn("Using localStorage fallback for courses");
      const saved = localStorage.getItem("user_selected_courses");
      return saved ? JSON.parse(saved) : [];
    }
  },

  async getUserCourseProgress(courseId: string, token: string): Promise<UserProgress> {
    return apiRequest<UserProgress>(
      buildApiUrl(`/api/fitness/users/me/progress?courseId=${courseId}`),
      {
        method: "GET",
        headers: {
          Authorization: `Bearer ${token}`,
        },
      }
    );
  },

  async getWorkoutProgress(
    courseId: string,
    workoutId: string,
    token: string
  ): Promise<{
    workoutId: string;
    workoutCompleted: boolean;
    progressData: number[];
  }> {
    return apiRequest<any>(
      buildApiUrl(`/api/fitness/users/me/progress?courseId=${courseId}&workoutId=${workoutId}`),
      {
        method: "GET",
        headers: {
          Authorization: `Bearer ${token}`,
        },
      }
    );
  },

  async addCourseToUser(courseId: string, token: string): Promise<{ message: string }> {
    try {
      return await apiRequest<{ message: string }>(
        buildApiUrl("/api/fitness/users/me/courses"),
        {
          method: "POST",
          headers: {
            Authorization: `Bearer ${token}`,
          },
          body: JSON.stringify({ courseId }),
        }
      );
    } catch (error) {
      console.warn("API add course failed, using localStorage fallback");
      const saved = localStorage.getItem("user_selected_courses");
      const courses = saved ? JSON.parse(saved) : [];
      if (!courses.includes(courseId)) {
        courses.push(courseId);
        localStorage.setItem("user_selected_courses", JSON.stringify(courses));
      }
      return { message: "Курс успешно добавлен! (локально)" };
    }
  },

  async removeCourseFromUser(courseId: string, token: string): Promise<{ message: string }> {
    try {
      return await apiRequest<{ message: string }>(
        buildApiUrl(`/api/fitness/users/me/courses/${courseId}`),
        {
          method: "DELETE",
          headers: {
            Authorization: `Bearer ${token}`,
          },
        }
      );
    } catch (error) {
      console.warn("API remove course failed, using localStorage fallback");
      const saved = localStorage.getItem("user_selected_courses");
      if (saved) {
        const courses = JSON.parse(saved).filter((id: string) => id !== courseId);
        localStorage.setItem("user_selected_courses", JSON.stringify(courses));
      }
      return { message: "Курс успешно удален! (локально)" };
    }
  },

  async resetCourseProgress(courseId: string, token: string): Promise<{ message: string }> {
    return apiRequest<{ message: string }>(
      buildApiUrl(`/api/fitness/courses/${courseId}/reset`),
      {
        method: "PATCH",
        headers: {
          Authorization: `Bearer ${token}`,
        },
      }
    );
  },
};
